@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-200: #d6d5d4;
  --color-neutral-400: #9ca3af;
  --color-neutral-600: #5f6368;
  --color-neutral-800: #333333;
  --color-neutral-950: #000000;
  --color-deep-orange: #28170e;
  --color-pale-blue: #e8eaed;
  --color-deep-yellow: #27251e;
  --color-cyan: #1a73e8;
  --color-deep-teal: #071f21;
  --color-deep-red: #450a0a;
  --color-teal: #016a71;
  --color-red: #e10600;
  --color-red-2: #a23544;
  --color-orange: #97431a;
  --color-orange-2: #825503;
  --color-deep-lime: #536300;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #000000;
  --color-text-muted: #9ca3af;
  --color-surface: #d6d5d4;
  --color-hairline: #5f6368;
  --color-accent: #28170e;
  --color-accent-2: #e8eaed;
  --color-accent-3: #27251e;

  --font-sans: "Apple SD Gothic Neo", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 0.625rem;
  --text-sm: 0.6875rem;
  --text-base: 0.75rem;
  --text-lg: 0.856875rem;
  --text-xl: 0.875rem;
  --text-2xl: 1rem;
  --text-3xl: 1.125rem;
  --text-4xl: 1.2rem;
  --text-5xl: 1.25rem;
  --text-6xl: 1.5rem;
  --text-7xl: 1.875rem;
  --text-8xl: 2.25rem;

  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-450: 450;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.2;
  --leading-snug: 1.25;
  --leading-normal: 1.33;
  --leading-relaxed: 1.43;
  --leading-loose: 1.5;
  --leading-looser: 1.6;
  --leading-loosest: 1.71;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -.05em;
  --tracking-tighter: -.025em;
  --tracking-tight: 0em;
  --tracking-normal: .25px;
  --tracking-wide: .3px;
  --tracking-wider: .18em;

  --radius-sm: .125rem;
  --radius-md: 4px;
  --radius-lg: .375rem;
  --radius-xl: .5rem;
  --radius-2xl: .75rem;
  --radius-3xl: 1rem;
  --radius-4xl: 1.25rem;
  --radius-full: 9999px;

  /* shadows, sorted by blur */
  --shadow-sm: 0 0 2px 2px #0096ff;

  --breakpoint-sm: 25.625rem;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 6, 8, 10, 12, 16, 20, 24, 32 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --super-color: var(--dark-super-color);
    --caution-color: var(--dark-caution-color);
    --warning-color: var(--dark-warning-color);
    --positive-color: var(--dark-positive-color);
    --negative-color: var(--dark-negative-color);
    --background-underlay-color: var(--dark-background-underlay-color);
    --background-base-color: var(--dark-background-base-color);
    --background-quiet-color: var(--dark-background-quiet-color);
    --background-subtle-color: var(--dark-background-subtle-color);
    --background-raised-color: var(--dark-background-raised-color);
    --background-inverse-color: var(--dark-background-inverse-color);
    --foreground-color: var(--dark-foreground-color);
    --foreground-quiet-color: var(--dark-foreground-quiet-color);
