    --foreground-subtle-color: var(--dark-foreground-subtle-color);
    --foreground-subtlest-color: var(--dark-foreground-subtlest-color);
    --foreground-inverse-color: var(--dark-foreground-inverse-color);
    --border-focus-neutral-color: var(--dark-border-focus-neutral-color);
    --button-color: var(--dark-button-color);
    --button-hover-color: var(--dark-button-hover-color);
    --button-active-color: var(--dark-button-active-color);
    --shadow-overlay-border: #ffffff1a;
    --offset-color: var(--dark-offset-color);
    --bg-inverse: var(--odin-dark-1000);
    --bg-soft: var(--odin-dark-1000-a-7);
    --bg-subtle: var(--odin-dark-1000-a-3½);
    --bg-base: var(--odin-dark-100);
